-- ===========================================
-- Catálogos globais de sugestão
-- Procedimentos, Insumos e Despesas Fixas
-- ===========================================

CREATE TABLE IF NOT EXISTS catalog_procedures (
  id           SERIAL PRIMARY KEY,
  code         TEXT NOT NULL UNIQUE,
  name         TEXT NOT NULL,
  category     TEXT,
  specialty    TEXT,
  type         TEXT,
  duration_min INT NOT NULL DEFAULT 30
);

ALTER TABLE catalog_procedures ENABLE ROW LEVEL SECURITY;
CREATE POLICY "catalog_procedures_read" ON catalog_procedures
  FOR SELECT USING (auth.role() = 'authenticated');

CREATE INDEX IF NOT EXISTS idx_catalog_proc_name ON catalog_procedures USING gin(to_tsvector('portuguese', name));
CREATE INDEX IF NOT EXISTS idx_catalog_proc_cat  ON catalog_procedures(category);
CREATE INDEX IF NOT EXISTS idx_catalog_proc_spec ON catalog_procedures(specialty);


CREATE TABLE IF NOT EXISTS catalog_stock_items (
  id              SERIAL PRIMARY KEY,
  code            TEXT NOT NULL UNIQUE,
  name            TEXT NOT NULL,
  category        TEXT,
  clinic_type     TEXT,
  presentation    TEXT,
  frequency_class TEXT
);

ALTER TABLE catalog_stock_items ENABLE ROW LEVEL SECURITY;
CREATE POLICY "catalog_stock_read" ON catalog_stock_items
  FOR SELECT USING (auth.role() = 'authenticated');

CREATE INDEX IF NOT EXISTS idx_catalog_stock_name ON catalog_stock_items USING gin(to_tsvector('portuguese', name));
CREATE INDEX IF NOT EXISTS idx_catalog_stock_cat  ON catalog_stock_items(category);


CREATE TABLE IF NOT EXISTS catalog_fixed_expenses (
  id              SERIAL PRIMARY KEY,
  code            TEXT NOT NULL UNIQUE,
  category        TEXT,
  description     TEXT NOT NULL,
  type            TEXT,
  periodicity     TEXT,
  estimated_value DECIMAL(10,2),
  recipient       TEXT
);

ALTER TABLE catalog_fixed_expenses ENABLE ROW LEVEL SECURITY;
CREATE POLICY "catalog_expenses_read" ON catalog_fixed_expenses
  FOR SELECT USING (auth.role() = 'authenticated');

CREATE INDEX IF NOT EXISTS idx_catalog_exp_name ON catalog_fixed_expenses USING gin(to_tsvector('portuguese', description));
CREATE INDEX IF NOT EXISTS idx_catalog_exp_cat  ON catalog_fixed_expenses(category);

